/**
 * Market Simulation CLI
 * Command-line interface for running market simulations.
 */

import { MarketSimulation } from './simulation';
import chalk from 'chalk';
import { Command } from 'commander';
import type { SimulationReport } from './types';
import { TimeSeriesStorage, createStorage } from './storage';
import { mean, stdDev, descriptiveStats } from './statistics';

interface CliOptions {
  ticks: number;
  delay: number;
  suppliers: number;
  demands: number;
  arbitrageurs: number;
  shocks: boolean;
  dbPath: string;
  report: boolean;
  agents: boolean;
}

function runSimulation(options: CliOptions): void {
  console.log(chalk.cyan.bold('═══ Market Simulation ═══'));
  console.log();

  const sim = new MarketSimulation({
    ticks: options.ticks,
    tickDelayMs: options.delay,
    initialPrice: 100,
    initialQuantity: 0,
    maxPrice: 500,
    minPrice: 10,
    shockProbability: options.shocks ? 0.05 : 0,
    dbPath: options.dbPath,
  });

  // Add agents
  console.log(chalk.gray('Initializing agents...'));

  for (let i = 0; i < options.suppliers; i++) {
    sim.addSupplier({ initialCapital: 50000, riskTolerance: 0.6 });
  }

  for (let i = 0; i < options.demands; i++) {
    sim.addDemand({ initialCapital: 50000, riskTolerance: 0.6 });
  }

  for (let i = 0; i < options.arbitrageurs; i++) {
    sim.addArbitrageur({ initialCapital: 100000, riskTolerance: 0.8 });
  }

  if (options.shocks) {
    sim.addShockAgent({ riskTolerance: 1.0 });
  }

  const totalAgents = options.suppliers + options.demands + options.arbitrageurs + (options.shocks ? 1 : 0);
  console.log(chalk.green(`✓ Initialized ${totalAgents} agents`));
  console.log();

  // Run simulation synchronously
  const startTime = Date.now();

  // Simulate with progress bar
  const renderProgress = (progress: number) => {
    const width = 40;
    const filled = Math.floor(width * progress);
    const bar = '█'.repeat(filled) + '░'.repeat(width - filled);
    const percent = Math.floor(progress * 100);
    process.stdout.write(`\r${chalk.gray('[')}${chalk.cyan(bar)}${chalk.gray(']')} ${percent}%`);
  };

  // Bootstrapped simulation with synchronous chunks
  const runProgressively = (tick: number): Promise<void> | void => {
    if (tick >= options.ticks) return;

    // Process tick (simplified for CLI)
    // In a real implementation, we'd call sim.runTick(tick)
    // For now, we'll just run full sync
  };

  // Run full simulation
  console.log(chalk.cyan('Running simulation...'));
  console.log();

  sim.run().then((report: SimulationReport) => {
    const duration = Date.now() - startTime;

    console.log(`\n${chalk.green('✓ Simulation complete')}`);
    console.log();

    // Summary
    if (options.report) {
      printReport(report);
    }

    // Agent details
    if (options.agents) {
      printAgentDetails(report);
    }

    // DB stats
    console.log(chalk.cyan.bold('═ Database Stats ═'));
    const stats = sim.getStats();
    console.log(`Market states: ${chalk.white(stats.marketStates)}`);
    console.log(`Agent states: ${chalk.white(stats.agentStates)}`);
    console.log(`Orders: ${chalk.white(stats.orders)}`);
    console.log(`Trades: ${chalk.white(stats.trades)}`);
    console.log(`Execution time: ${chalk.white(`${duration}ms`)}`);
    console.log();

    console.log(chalk.green.bold('Simulation complete! Data saved to:') + ' ' + chalk.dim(report.config.dbPath));

    // Cleanup
    sim.cleanup();
  });
}

function printReport(report: SimulationReport): void {
  console.log(chalk.cyan.bold('═ Simulation Report ═'));
  console.log();

  // Price summary
  const priceChange = report.priceChange;
  const changeColor = priceChange >= 0 ? chalk.green : chalk.red;
  const arrow = priceChange >= 0 ? '▲' : '▼';

  console.log(`${chalk.bold('Price')} ${changeColor(`${arrow} ${priceChange.toFixed(2)}%`)}`);
  console.log(`  Final:    ${chalk.white(report.finalState.price.toFixed(2))}`);
  console.log(`  Mean:     ${chalk.white(report.priceStats.mean.toFixed(2))}`);
  console.log(`  Range:    ${chalk.white(`${report.priceStats.min.toFixed(2)} - ${report.priceStats.max.toFixed(2)}`)}`);
  console.log(`  Std Dev:  ${chalk.white(report.priceStats.stdDev.toFixed(2))}`);
  console.log();

  // Trades
  console.log(`${chalk.bold('Trades')} ${chalk.white(report.totalTrades.toString())}`);
  console.log();

  // Agents
  if (report.agentSummaries.length > 0) {
    const winning = report.agentSummaries.filter(a => a.totalProfit > 0).length;
    const losing = report.agentSummaries.filter(a => a.totalProfit < 0).length;
    const totalProfit = report.agentSummaries.reduce((sum, a) => sum + a.totalProfit, 0);

    console.log(`${chalk.bold('Agents')} ${chalk.white(report.agentSummaries.length.toString())}`);
    console.log(`  Winners:  ${chalk.green(winning.toString())}`);
    console.log(`  Losers:   ${chalk.red(losing.toString())}`);
    console.log(`  Net P&L:  ${totalProfit >= 0 ? chalk.green : chalk.red}$${totalProfit.toFixed(2)}`);
  }
  console.log();
}

function printAgentDetails(report: SimulationReport): void {
  console.log(chalk.cyan.bold('═ Agent Performance ═'));
  console.log();

  const byType = report.agentSummaries.reduce((acc, agent) => {
    if (!acc[agent.type]) acc[agent.type] = [];
    acc[agent.type].push(agent);
    return acc;
  }, {} as Record<string, typeof report.agentSummaries>);

  for (const [type, agents] of Object.entries(byType)) {
    const color = type === 'supplier' ? chalk.cyan 
      : type === 'demand' ? chalk.magenta 
      : type === 'arbitrageur' ? chalk.yellow 
      : chalk.gray;

    console.log(color.bold(`${type.charAt(0).toUpperCase() + type.slice(1)}s`));

    const avgProfit = agents.reduce((sum, a) => sum + a.totalProfit, 0) / agents.length;
    const avgTrades = agents.reduce((sum, a) => sum + a.tradesExecuted, 0) / agents.length;
    const avgROI = agents.reduce((sum, a) => sum + a.returnOnInvestment, 0) / agents.length;

    console.log(`  Average Profit:  ${avgProfit >= 0 ? chalk.green : chalk.red}$${avgProfit.toFixed(2)}`);
    console.log(`  Average Trades: ${chalk.white(avgTrades.toFixed(1))}`);
    console.log(`  Avg ROI:        ${avgROI >= 0 ? chalk.green : chalk.red}${avgROI.toFixed(2)}%`);

    // Top performer
    const top = agents.reduce((max, a) => a.totalProfit > max.totalProfit ? a : max, agents[0]);
    if (top) {
      console.log(`  Top performer:  ${chalk.white(top.agentId)} (+$${top.totalProfit.toFixed(2)})`);
    }
    console.log();
  }
}

// Simple CLI without commander for now
const [, , ...args] = process.argv;
const options: CliOptions = {
  ticks: 100,
  delay: 0,
  suppliers: 3,
  demands: 3,
  arbitrageurs: 2,
  shocks: true,
  dbPath: './market_simulation.db',
  report: true,
  agents: true,
};

// Parse args
for (let i = 0; i < args.length; i++) {
  switch (args[i]) {
    case '--ticks':
    case '-t':
      options.ticks = parseInt(args[++i]) || 100;
      break;
    case '--suppliers':
    case '-s':
      options.suppliers = parseInt(args[++i]) || 3;
      break;
    case '--demands':
    case '-d':
      options.demands = parseInt(args[++i]) || 3;
      break;
    case '--arbitrageurs':
    case '-a':
      options.arbitrageurs = parseInt(args[++i]) || 2;
      break;
    case '--no-shocks':
      options.shocks = false;
      break;
    case '--no-report':
      options.report = false;
      break;
    case '--help':
    case '-h':
      console.log('Market Simulation CLI');
      console.log();
      console.log('Usage: tsx cli.ts [options]');
      console.log();
      console.log('Options:');
      console.log('  -t, --ticks <n>         Number of ticks (default: 100)');
      console.log('  -s, --suppliers <n>     Number of supplier agents');
      console.log('  -d, --demands <n>       Number of demand agents');
      console.log('  -a, --arbitrageurs <n>  Number of arbitrageur agents');
      console.log('  --no-shocks            Disable external shocks');
      console.log('  --no-report            Skip report output');
      console.log('  -h, --help             Show this help');
      process.exit(0);
      break;
  }
}

// Run simulation
runSimulation(options);
EOF"}

