 * - Matching engine with price-time priority
 */

// Core components
export { EventBus } from './event_bus';
export { TimeSeriesStorage, createStorage } from './storage';
export { MarketSimulation } from './simulation';
export { MatchingEngine } from './matching_engine';

// Statistics
export {
  mean,
  median,
  stdDev,
  skewness,
  kurtosis,
  descriptiveStats,
  linearRegression,
  analyzeTrend,
  rollingAverage,
  exponentialMovingAverage,
  bollingerBands,
  calculateReturns,
  historicalVolatility,
  analyzeVolatility,
  correlation,
  autocorrelation,
  sharpeRatio,
  maxDrawdown,
  calculateRSI,
  fibonacciRetracement,
  findSupportResistance,
} from './statistics';

// Agents
export { BaseAgent } from './agents/base';
export { SupplierAgent } from './agents/supplier';
export { DemandAgent } from './agents/demand';
export { ArbitrageurAgent } from './agents/arbitrageur';
export { ExternalShockAgent } from './agents/external';

// Types
export type {
  MarketState,
  Order,
  Trade,
  AgentType,
  AgentConfig,
  AgentState,
  AgentDecision,
  EventType,
  MarketEvent,
  PriceUpdatePayload,
  ExternalShockPayload,
  ArbitragePayload,
  TimeSeriesPoint,
  DescriptiveStats,
  TrendAnalysis,
  VolatilityAnalysis,
  SimulationConfig,
  SimulationReport,
  AgentSummary,
  Snapshot,
  Listener,
} from './types';

/**
 * Default simulation configuration
 */
export const defaultConfig: Partial<SimulationConfig> = {
  ticks: 100,
  tickDelayMs: 0,
  initialPrice: 100,
  initialQuantity: 1000,
  maxPrice: 500,
  minPrice: 10,
  shockProbability: 0.05,
  dbPath: './market_simulation.db',
};

/**
 * Create a standard simulation with balanced agents
 */
export function createStandardSimulation(): MarketSimulation {
  const sim = new MarketSimulation(defaultConfig);

  // Add 3 suppliers
  sim.addSupplier({ riskTolerance: 0.6, reactionSpeed: 2 });
  sim.addSupplier({ riskTolerance: 0.7, reactionSpeed: 2 });
  sim.addSupplier({ riskTolerance: 0.5, reactionSpeed: 3 });

  // Add 3 demand agents
  sim.addDemand({ riskTolerance: 0.6, reactionSpeed: 2 });
  sim.addDemand({ riskTolerance: 0.7, reactionSpeed: 2 });
  sim.addDemand({ riskTolerance: 0.8, reactionSpeed: 1 });

  // Add 2 arbitrageurs
  sim.addArbitrageur({ riskTolerance: 0.8, reactionSpeed: 1 });
  sim.addArbitrageur({ riskTolerance: 0.9, reactionSpeed: 1 });

  // Add external shock agent
  sim.addShockAgent({ riskTolerance: 1.0 });

  return sim;
}
