/**
 * Market Simulation Engine
 * Main simulation orchestrator that coordinates agents,
 * matching engine, storage, and event bus.
 */

import { EventBus } from './event_bus';
import { TimeSeriesStorage } from './storage';
import { MatchingEngine } from './matching_engine';
import { SupplierAgent } from './agents/supplier';
import { DemandAgent } from './agents/demand';
import { ArbitrageurAgent } from './agents/arbitrageur';
import { ExternalShockAgent } from './agents/external';
import type { 
  BaseAgent 
} from './agents/base';
import type {
  SimulationConfig,
  SimulationReport,
  MarketState,
  SimulationConfig,
  AgentConfig,
  AgentSummary,
  Order,
  AgentDecision,
} from './types';
import { descriptiveStats, analyzeVolatility, analyzeTrend, maxDrawdown, calculateReturns } from './statistics';

export class MarketSimulation {
  private config: SimulationConfig;
  private eventBus: EventBus;
  private storage: TimeSeriesStorage;
  private matchingEngine: MatchingEngine;
  private agents: BaseAgent[] = [];
  private state: MarketState;
  private priceHistory: number[] = [];
  private volumeHistory: number[] = [];
  private startTime: number = 0;

  constructor(config: Partial<SimulationConfig> = {}) {
    const fullConfig: SimulationConfig = {
      ticks: 100,
      tickDelayMs: 0,
      initialPrice: 100,
      initialQuantity: 1000,
      maxPrice: 500,
      minPrice: 10,
      shockProbability: 0.05,
      dbPath: './market_simulation.db',
      ...config,
    };

    this.config = fullConfig;
    this.eventBus = new EventBus();

    this.storage = new TimeSeriesStorage({
      dbPath: this.config.dbPath,
      inMemory: false,
      maxSnapshots: 100,
    });

    this.matchingEngine = new MatchingEngine(this.eventBus);

    this.state = {
